// tensor.h
struct Tensor {
  float* data; // Raw pointer to flat memory buffer
  std::vector<int> shape; // Dimensions of the tensor
  std::vector<int> strides; // Pre-calculated multipliers for each dimension

  // Constructor: Initializes a tensor view from a raw buffer and shape.
  // Calculates row-major strides automatically.
  Tensor(float* data, std::vector<int> shape);

  // Accesses an element at given N-dimensional indices.
  float at(std::vector<int> indices);
};

// tensor.cpp
Tensor::Tensor(float* new_data, std::vector<int> new_shape)
    : data(new_data), shape(new_shape) {
  strides.resize(shape.size());
  if (!shape.empty()) {
    strides.back() = 1; // Last dimension is contiguous
    for (int i = shape.size() - 2; i >= 0; --i) {
      strides[i] = strides[i+1] * shape[i+1];
    }
  }
}

float Tensor::at(std::vector<int> indices) {
  int offset = 0;
  for (int i = 0; i < indices.size(); ++i) {
    offset += indices[i] * strides[i];
  }
  return data[offset];
}
